import { createLove2DApp } from '@reactjit/native';

const app = createLove2DApp();
app.render(<App />);

-- Internally, createLove2DApp:
-- 1. Creates a NativeBridge (QuickJS FFI transport)
-- 2. Creates a reconciler root via createRoot()
-- 3. Wraps your element in BridgeProvider and RendererProvider
-- 4. Wires up the __mount / __deferMount protocol for Lua init
-- 5. Returns { render, stop, bridge }

import { useBridge, useLove, useLoveRPC, useLoveState } from '@reactjit/core';

// All hooks consume IBridge from context -- transport-agnostic
const [gameState, send] = useLove('game:state', { ready: false });
const getNearby = useLoveRPC<Entity[]>('getNearby');
const [health, setHealth] = useLoveState('player.health', 100);

// Send commands
send('player:move', { x: 100, y: 200 });

// RPC calls
const nearby = await getNearby({ x: 100, y: 200, range: 500 });

